package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * A generator that creates test cases from node specifications.
 * Generates both exhaustive test cases (all possible combinations) and random test cases.
 */
public class BaseSetGenerator {

    private final List<APyNode<?>> nodes;
    private final int numRand;
    private Set<TestCase> currentTests;

    /**
     * Constructor for BaseSetGenerator.
     *
     * @param nodes the list of argument nodes
     * @param numRand the number of random tests to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = new ArrayList<>(nodes);
        this.numRand = numRand;
        this.currentTests = new HashSet<>();
    }

    /**
     * Generates all exhaustive test cases by computing the Cartesian product
     * of exhaustive values from all argument nodes.
     *
     * @return a set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        this.currentTests = new HashSet<>();

        if (this.nodes.isEmpty()) {
            return this.currentTests;
        }

        // Generate all exhaustive values for each node
        List<Set<APyObj>> allValues = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            Set<? extends APyObj> vals = node.genExVals();
            allValues.add(new HashSet<>(vals));
        }

        // Compute Cartesian product
        generateCartesianProduct(allValues, 0, new ArrayList<>(), this.currentTests);

        return new HashSet<>(this.currentTests);
    }

    /**
     * Helper method to generate the Cartesian product of multiple sets.
     *
     * @param allValues list of value sets for each argument
     * @param index current argument index
     * @param current current combination being built
     * @param result set to add completed combinations to
     */
    private void generateCartesianProduct(List<Set<APyObj>> allValues, int index,
                                         List<APyObj> current, Set<TestCase> result) {
        if (index == allValues.size()) {
            result.add(new TestCase(new ArrayList<>(current)));
            return;
        }

        for (APyObj val : allValues.get(index)) {
            current.add(val);
            generateCartesianProduct(allValues, index + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates random test cases.
     * The number of tests to generate is determined by numRand passed to the constructor.
     * Attempts to generate numRand unique tests that don't overlap with exhaustive tests.
     *
     * @return a set of random test cases (up to numRand tests)
     */
    public Set<TestCase> genRandTests() {
        Set<TestCase> result = new HashSet<>();
        Set<TestCase> allSeenTests = new HashSet<>(this.currentTests);

        int attempts = 0;
        int maxAttempts = this.numRand * 10; // Reasonable limit to avoid infinite loops

        while (result.size() < this.numRand && attempts < maxAttempts) {
            TestCase test = genRandTest();
            attempts++;
            // Avoid duplicates with exhaustive tests and previously generated random tests
            if (!allSeenTests.contains(test)) {
                result.add(test);
                allSeenTests.add(test);
            }
        }

        return result;
    }

    /**
     * Helper method to generate a single random test case.
     *
     * @return a random test case
     */
    private TestCase genRandTest() {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            args.add(node.genRandVal());
        }
        return new TestCase(args);
    }

    /**
     * Generates the base set of tests: all exhaustive tests plus random tests.
     * Returns a list combining genExTests() and genRandTests().
     *
     * @return a list of all exhaustive and random test cases
     */
    public List<TestCase> genBaseSet() {
        // First generate exhaustive tests
        Set<TestCase> exTests = genExTests();

        // Then generate random tests
        Set<TestCase> randTests = genRandTests();

        // Combine and return as list
        List<TestCase> result = new ArrayList<>(exTests);
        result.addAll(randTests);

        return result;
    }
}

package main.rice.node;

import main.rice.obj.AIterablePyObj;

/**
 * An abstract class representing an iterable Python node (list, tuple, set, string, or dict).
 * Iterable nodes contain child nodes that represent the element/key/value types.
 *
 * @param <ValueType> the type of iterable values this node generates
 */
public abstract class AIterablePyNode<ValueType extends AIterablePyObj<?>>
    extends APyNode<ValueType> {

    /**
     * Returns the left child node (element/key type for iterables).
     *
     * @return the left child node
     */
    public abstract APyNode<?> getLeftChild();

    /**
     * Returns the right child node if this iterable has two child types (dict), null otherwise.
     *
     * @return the right child node or null
     */
    public APyNode<?> getRightChild() {
        return null;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class representing a Python domain node that can generate values.
 * Each node represents a domain of possible values and can generate exhaustive or random values.
 *
 * @param <ValueType> the type of values this node generates
 */
public abstract class APyNode<ValueType extends APyObj> {

    /**
     * Returns the exhaustive domain specification.
     *
     * @return the exhaustive domain specification
     */
    public abstract Object getExDomain();

    /**
     * Returns the random domain specification.
     *
     * @return the random domain specification
     */
    public abstract Object getRanDomain();

    /**
     * Sets the exhaustive domain specification.
     *
     * @param exDomain the exhaustive domain to set
     */
    public abstract void setExDomain(Object exDomain);

    /**
     * Sets the random domain specification.
     *
     * @param ranDomain the random domain to set
     */
    public abstract void setRanDomain(Object ranDomain);

    /**
     * Generates all exhaustive values from this node's exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<ValueType> genExVals();

    /**
     * Generates a single random value from this node's random domain.
     *
     * @return a random value
     */
    public abstract ValueType genRandVal();

    /**
     * Returns the left child node if this is an iterable node, null otherwise.
     *
     * @return the left child node or null
     */
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns the right child node if this is an iterable node with two children, null otherwise.
     *
     * @return the right child node or null
     */
    public APyNode<?> getRightChild() {
        return null;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;;

/**
 * A node representing Python dictionaries that can generate dictionary values of various sizes.
 * The domain is specified as a list of integers representing the sizes of dictionaries to generate.
 * Dictionaries have two child nodes: one for keys and one for values.
 *
 * @param <KeyType> the type of keys in the dictionary
 * @param <ValueType> the type of values in the dictionary
 */
public class PyDictNode<KeyType extends APyObj, ValueType extends APyObj>
    extends APyNode<PyDictObj<KeyType, ValueType>> {

    private APyNode<KeyType> keyNode;
    private APyNode<ValueType> valueNode;
    private List<Integer> exDomain;
    private List<Integer> ranDomain;

    /**
     * Constructor for PyDictNode with given key and value nodes.
     *
     * @param keyNode the node representing the type of keys in the dictionary
     * @param valueNode the node representing the type of values in the dictionary
     */
    public PyDictNode(APyNode<KeyType> keyNode, APyNode<ValueType> valueNode) {
        this.keyNode = keyNode;
        this.valueNode = valueNode;
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    @Override
    public Object getExDomain() {
        return this.exDomain;
    }

    @Override
    public Object getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setExDomain(Object exDomain) {
        this.exDomain = (List<Integer>) exDomain;
    }

    @Override
    public void setRanDomain(Object ranDomain) {
        this.ranDomain = (List<Integer>) ranDomain;
    }

    /**
     * Sets the exhaustive domain specification.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain specification.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return this.keyNode;
    }

    @Override
    public APyNode<?> getRightChild() {
        return this.valueNode;
    }

    @Override
    public Set<PyDictObj<KeyType, ValueType>> genExVals() {
        Set<PyDictObj<KeyType, ValueType>> result = new HashSet<>();

        // Generate all combinations of key-value pairs for each size in the domain
        for (Integer size : this.exDomain) {
            if (size == 0) {
                // Empty dict
                result.add(new PyDictObj<>(new HashMap<>()));
            } else {
                // Generate all combinations of key-value pairs of the given size
                Set<KeyType> keyVals = this.keyNode.genExVals();
                Set<ValueType> valueVals = this.valueNode.genExVals();
                List<KeyType> keyList = new ArrayList<>(keyVals);
                List<ValueType> valueList = new ArrayList<>(valueVals);

                if (size <= keyList.size()) {
                    // Generate all combinations of key-value pairs without key replacement
                    generateCombinations(keyList, valueList, size, new HashMap<>(), 0, result);
                }
            }
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of key-value pairs.
     * Keys must be unique (no replacement), values can repeat.
     *
     * @param keys the list of available keys
     * @param values the list of available values
     * @param size the desired size of the dictionary
     * @param current the current dictionary being built
     * @param startKeyIdx the index to start considering keys from
     * @param result the set to add completed dictionaries to
     */
    private void generateCombinations(List<KeyType> keys, List<ValueType> values,
                                     int size, Map<KeyType, ValueType> current,
                                     int startKeyIdx,
                                     Set<PyDictObj<KeyType, ValueType>> result) {
        if (current.size() == size) {
            result.add(new PyDictObj<>(new HashMap<>(current)));
            return;
        }

        for (int i = startKeyIdx; i < keys.size(); i++) {
            KeyType key = keys.get(i);
            for (ValueType value : values) {
                current.put(key, value);
                generateCombinations(keys, values, size, current, i + 1, result);
                current.remove(key);
            }
        }
    }

    @Override
    public PyDictObj<KeyType, ValueType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return new PyDictObj<>(new HashMap<>());
        }

        // Pick a random size from the domain
        int idx = ThreadLocalRandom.current().nextInt(this.ranDomain.size());
        int size = this.ranDomain.get(idx);

        // Generate a dictionary of that size with random key-value pairs
        Map<KeyType, ValueType> dict = new HashMap<>();

        // Generate random unique keys (without replacement)
        // Try to generate 'size' unique random keys
        // Since we use random values, we need a reasonable attempt limit
        int attempts = 0;
        int maxAttempts = size * 10; // Allow multiple attempts to get unique keys
        while (dict.size() < size && attempts < maxAttempts) {
            KeyType key = this.keyNode.genRandVal();
            ValueType value = this.valueNode.genRandVal();
            dict.put(key, value);
            attempts++;
        }

        return new PyDictObj<>(dict);
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;

/**
 * A node representing Python integers that can generate integer values.
 * Domains are specified as lists of integers representing the values to generate.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    private List<Integer> exDomain;
    private List<Integer> ranDomain;

    /**
     * Constructor for PyIntNode with no initial domains.
     */
    public PyIntNode() {
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    @Override
    public Object getExDomain() {
        return this.exDomain;
    }

    @Override
    public Object getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setExDomain(Object exDomain) {
        this.exDomain = (List<Integer>) exDomain;
    }

    @Override
    public void setRanDomain(Object ranDomain) {
        this.ranDomain = (List<Integer>) ranDomain;
    }

    /**
     * Returns the exhaustive domain specification as a List<Integer>.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomainList() {
        return this.exDomain;
    }

    /**
     * Returns the random domain specification as a List<Integer>.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomainList() {
        return this.ranDomain;
    }

    /**
     * Sets the exhaustive domain specification.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain specification.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    @Override
    public PyIntObj genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return null;
        }
        int idx = ThreadLocalRandom.current().nextInt(this.ranDomain.size());
        Integer val = this.ranDomain.get(idx);
        return new PyIntObj(val);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyListObj;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;

/**
 * A node representing Python lists that can generate list values of various lengths.
 * The domain is specified as a list of integers representing the lengths of lists to generate.
 * Lists allow duplicate elements.
 *
 * @param <InnerType> the type of elements in the list
 */
public class PyListNode<InnerType extends APyObj>
    extends AIterablePyNode<PyListObj<InnerType>> {

    private APyNode<InnerType> elementNode;
    private List<Integer> exDomain;
    private List<Integer> ranDomain;

    /**
     * Constructor for PyListNode with a given element node.
     *
     * @param elementNode the node representing the type of elements in the list
     */
    public PyListNode(APyNode<InnerType> elementNode) {
        this.elementNode = elementNode;
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    @Override
    public Object getExDomain() {
        return this.exDomain;
    }

    @Override
    public Object getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setExDomain(Object exDomain) {
        this.exDomain = (List<Integer>) exDomain;
    }

    @Override
    public void setRanDomain(Object ranDomain) {
        this.ranDomain = (List<Integer>) ranDomain;
    }

    /**
     * Sets the exhaustive domain specification.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain specification.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return this.elementNode;
    }

    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        Set<PyListObj<InnerType>> result = new HashSet<>();

        // Generate all combinations of elements for each length in the domain
        for (Integer length : this.exDomain) {
            if (length == 0) {
                // Empty list
                result.add(new PyListObj<>(new ArrayList<>()));
            } else {
                // Generate all combinations of elements of the given length
                Set<InnerType> elementVals = this.elementNode.genExVals();
                List<InnerType> elementList = new ArrayList<>(elementVals);

                // Generate all combinations with replacement (cartesian product)
                generateCombinations(elementList, length, new ArrayList<>(), result);
            }
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of elements with a given length.
     * Uses recursion to build combinations with replacement.
     *
     * @param elements the list of available elements
     * @param length the desired length of the combination
     * @param current the current combination being built
     * @param result the set to add completed combinations to
     */
    private void generateCombinations(List<InnerType> elements, int length,
                                     List<InnerType> current,
                                     Set<PyListObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyListObj<>(new ArrayList<>(current)));
            return;
        }

        for (InnerType elem : elements) {
            current.add(elem);
            generateCombinations(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }

    @Override
    public PyListObj<InnerType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return new PyListObj<>(new ArrayList<>());
        }

        // Pick a random length from the domain
        int idx = ThreadLocalRandom.current().nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(idx);

        // Generate a list of that length with random elements
        List<InnerType> list = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            list.add(this.elementNode.genRandVal());
        }

        return new PyListObj<>(list);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PySetObj;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;;

/**
 * A node representing Python sets that can generate set values of various sizes.
 * The domain is specified as a list of integers representing the sizes of sets to generate.
 * Sets do not allow duplicate elements, so combinations are generated without replacement.
 *
 * @param <InnerType> the type of elements in the set
 */
public class PySetNode<InnerType extends APyObj>
    extends AIterablePyNode<PySetObj<InnerType>> {

    private APyNode<InnerType> elementNode;
    private List<Integer> exDomain;
    private List<Integer> ranDomain;

    /**
     * Constructor for PySetNode with a given element node.
     *
     * @param elementNode the node representing the type of elements in the set
     */
    public PySetNode(APyNode<InnerType> elementNode) {
        this.elementNode = elementNode;
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    @Override
    public Object getExDomain() {
        return this.exDomain;
    }

    @Override
    public Object getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setExDomain(Object exDomain) {
        this.exDomain = (List<Integer>) exDomain;
    }

    @Override
    public void setRanDomain(Object ranDomain) {
        this.ranDomain = (List<Integer>) ranDomain;
    }

    /**
     * Sets the exhaustive domain specification.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain specification.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return this.elementNode;
    }

    @Override
    public Set<PySetObj<InnerType>> genExVals() {
        Set<PySetObj<InnerType>> result = new HashSet<>();

        // Generate all combinations of elements for each size in the domain
        for (Integer size : this.exDomain) {
            if (size == 0) {
                // Empty set
                result.add(new PySetObj<>(new HashSet<>()));
            } else {
                // Generate all combinations of elements of the given size
                Set<InnerType> elementVals = this.elementNode.genExVals();
                List<InnerType> elementList = new ArrayList<>(elementVals);

                if (size <= elementList.size()) {
                    // Generate all combinations without replacement (subsets)
                    generateCombinations(elementList, size, new HashSet<>(), 0, result);
                }
            }
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of elements without replacement.
     * Uses recursion to build subsets of a given size.
     *
     * @param elements the list of available elements
     * @param size the desired size of the subset
     * @param current the current subset being built
     * @param startIdx the index to start considering elements from
     * @param result the set to add completed combinations to
     */
    private void generateCombinations(List<InnerType> elements, int size,
                                     Set<InnerType> current, int startIdx,
                                     Set<PySetObj<InnerType>> result) {
        if (current.size() == size) {
            result.add(new PySetObj<>(new HashSet<>(current)));
            return;
        }

        for (int i = startIdx; i < elements.size(); i++) {
            current.add(elements.get(i));
            generateCombinations(elements, size, current, i + 1, result);
            current.remove(elements.get(i));
        }
    }

    @Override
    public PySetObj<InnerType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return new PySetObj<>(new HashSet<>());
        }

        // Pick a random size from the domain
        int idx = ThreadLocalRandom.current().nextInt(this.ranDomain.size());
        int size = this.ranDomain.get(idx);

        // Generate a set of that size with random elements
        Set<InnerType> set = new HashSet<>();

        // Generate random unique elements (without replacement)
        // Try to generate 'size' unique random elements
        // Since we use random values, we need a reasonable attempt limit
        int attempts = 0;
        int maxAttempts = size * 10; // Allow multiple attempts to get unique values
        while (set.size() < size && attempts < maxAttempts) {
            InnerType elem = this.elementNode.genRandVal();
            set.add(elem);
            attempts++;
        }

        return new PySetObj<>(set);
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;;

/**
 * A node representing Python strings that can generate string values of various lengths.
 * The domain is specified as a list of integers representing the lengths of strings to generate.
 * Strings allow duplicate characters and work with PyCharObj.
 */
public class PyStringNode extends AIterablePyNode<PyStringObj> {

    private String charDomain;
    private List<Integer> exDomain;
    private List<Integer> ranDomain;

    /**
     * Constructor for PyStringNode with a given character domain string.
     *
     * @param charDomain the string containing the characters that can appear in generated strings
     */
    public PyStringNode(String charDomain) {
        this.charDomain = charDomain;
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    @Override
    public Object getExDomain() {
        return this.exDomain;
    }

    @Override
    public Object getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setExDomain(Object exDomain) {
        this.exDomain = (List<Integer>) exDomain;
    }

    @Override
    public void setRanDomain(Object ranDomain) {
        this.ranDomain = (List<Integer>) ranDomain;
    }

    /**
     * Sets the exhaustive domain specification.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain specification.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();

        // Convert charDomain string to PyCharObj list
        List<PyCharObj> charList = new ArrayList<>();
        for (char c : this.charDomain.toCharArray()) {
            charList.add(new PyCharObj(c));
        }

        // Generate all combinations of characters for each length in the domain
        for (Integer length : this.exDomain) {
            if (length == 0) {
                // Empty string
                result.add(new PyStringObj(new ArrayList<>()));
            } else {
                // Generate all combinations with replacement (cartesian product)
                generateCombinations(charList, length, new ArrayList<>(), result);
            }
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of characters with a given length.
     * Uses recursion to build combinations with replacement.
     *
     * @param chars the list of available characters
     * @param length the desired length of the combination
     * @param current the current combination being built
     * @param result the set to add completed combinations to
     */
    private void generateCombinations(List<PyCharObj> chars, int length,
                                     List<PyCharObj> current,
                                     Set<PyStringObj> result) {
        if (current.size() == length) {
            result.add(new PyStringObj(new ArrayList<>(current)));
            return;
        }

        for (PyCharObj ch : chars) {
            current.add(ch);
            generateCombinations(chars, length, current, result);
            current.remove(current.size() - 1);
        }
    }

    @Override
    public PyStringObj genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return new PyStringObj(new ArrayList<>());
        }

        // Pick a random length from the domain
        int lenIdx = ThreadLocalRandom.current().nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(lenIdx);

        // Convert charDomain string to PyCharObj list
        List<PyCharObj> charList = new ArrayList<>();
        for (char c : this.charDomain.toCharArray()) {
            charList.add(new PyCharObj(c));
        }

        // Generate a string of that length with random characters
        List<PyCharObj> string = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            int idx = ThreadLocalRandom.current().nextInt(charList.size());
            string.add(charList.get(idx));
        }

        return new PyStringObj(string);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyTupleObj;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;;

/**
 * A node representing Python tuples that can generate tuple values of various lengths.
 * The domain is specified as a list of integers representing the lengths of tuples to generate.
 * Like lists, tuples allow duplicate elements.
 *
 * @param <InnerType> the type of elements in the tuple
 */
public class PyTupleNode<InnerType extends APyObj>
    extends AIterablePyNode<PyTupleObj<InnerType>> {

    private APyNode<InnerType> elementNode;
    private List<Integer> exDomain;
    private List<Integer> ranDomain;

    /**
     * Constructor for PyTupleNode with a given element node.
     *
     * @param elementNode the node representing the type of elements in the tuple
     */
    public PyTupleNode(APyNode<InnerType> elementNode) {
        this.elementNode = elementNode;
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    @Override
    public Object getExDomain() {
        return this.exDomain;
    }

    @Override
    public Object getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setExDomain(Object exDomain) {
        this.exDomain = (List<Integer>) exDomain;
    }

    @Override
    public void setRanDomain(Object ranDomain) {
        this.ranDomain = (List<Integer>) ranDomain;
    }

    /**
     * Sets the exhaustive domain specification.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Sets the random domain specification.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return this.elementNode;
    }

    @Override
    public Set<PyTupleObj<InnerType>> genExVals() {
        Set<PyTupleObj<InnerType>> result = new HashSet<>();

        // Generate all combinations of elements for each length in the domain
        for (Integer length : this.exDomain) {
            if (length == 0) {
                // Empty tuple
                result.add(new PyTupleObj<>(new ArrayList<>()));
            } else {
                // Generate all combinations of elements of the given length
                Set<InnerType> elementVals = this.elementNode.genExVals();
                List<InnerType> elementList = new ArrayList<>(elementVals);

                // Generate all combinations with replacement (cartesian product)
                generateCombinations(elementList, length, new ArrayList<>(), result);
            }
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of elements with a given length.
     * Uses recursion to build combinations with replacement.
     *
     * @param elements the list of available elements
     * @param length the desired length of the combination
     * @param current the current combination being built
     * @param result the set to add completed combinations to
     */
    private void generateCombinations(List<InnerType> elements, int length,
                                     List<InnerType> current,
                                     Set<PyTupleObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyTupleObj<>(new ArrayList<>(current)));
            return;
        }

        for (InnerType elem : elements) {
            current.add(elem);
            generateCombinations(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }

    @Override
    public PyTupleObj<InnerType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return new PyTupleObj<>(new ArrayList<>());
        }

        // Pick a random length from the domain
        int idx = ThreadLocalRandom.current().nextInt(this.ranDomain.size());
        int length = this.ranDomain.get(idx);

        // Generate a tuple of that length with random elements
        List<InnerType> tuple = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            tuple.add(this.elementNode.genRandVal());
        }

        return new PyTupleObj<>(tuple);
    }
}

package main.rice.test;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * A test case consisting of a list of arguments.
 * Each TestCase represents a single test with a specific set of argument values.
 */
public class TestCase {

    /**
     * The list of arguments for this test case.
     */
    private final List<APyObj> args;

    /**
     * Constructor for TestCase with a given list of arguments.
     *
     * @param args the arguments for this test case
     */
    public TestCase(List<APyObj> args) {
        this.args = new ArrayList<>(args);
    }

    /**
     * Returns the list of arguments for this test case.
     *
     * @return the list of arguments
     */
    public List<APyObj> getArgs() {
        return new ArrayList<>(this.args);
    }

    /**
     * Compares this TestCase to another object for equality.
     * Two TestCases are equal if they have the same arguments in the same order.
     *
     * @param obj the object to compare against
     * @return true if obj is a TestCase with equal arguments; false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase other)) {
            return false;
        }
        return this.args.equals(other.args);
    }

    /**
     * Computes a hash code for this TestCase based on its arguments.
     *
     * @return the hash code for this TestCase
     */
    @Override
    public int hashCode() {
        return this.args.hashCode();
    }

    /**
     * Returns a string representation of this TestCase.
     *
     * @return a string representation of this TestCase
     */
    @Override
    public String toString() {
        return "TestCase(" + this.args + ")";
    }
}

